INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (874, 184815, 10, 1417, '再听彭军', '今天我听了久违的彭军，熟悉的声音，温暖的感觉。听着他说的话题，很有感觉。
<br>  他的节目拌我走过了整个高中生涯。当初是几个同学拉我一起分享的，并没有太在意，只是抱着听听看的心情。没想到，这一听就是三年，从不间断。每每听到他的声音就会有很舒服的感觉，淡淡的忧伤，湿湿的味道。
<br>  整个高三我就是在这样声音中度过，并不真正的快乐，只是在生活中找动力，让我可以继续读书，继续有理想，继续生活着。日复一日，我也毕业了。毕业后，我没有再听过彭军，真的，一点也没有。我也不知道是怎么过的。只是在某个巧合的时间里，我又一次听到了彭军，这时我才意识到我有两个多月没听到彭军了。从这以后我一直提醒我自己要听要听，可都因为这样那样的事给耽误了。直到今天，我终于再一次听到了彭军。今天是9月25日，还是彭军舒服的声音，很有熟悉的味道。话题还是那么的接近我们，我在他的声音中思考，在播放的音乐中畅游。想起同学，想起往事，想起我那混日子时的不快乐。
<br>  高三的感觉，怎么说呢？最痛苦的是每天要有意识的提醒自己是高三的学生，要努力啊，要拼，要写很多的练习，要面对来自各方的压力，虽然他们是善意的，但我还是觉得没必要。最害怕的是我居然没有任何感觉我即将高考，即将面临激烈甚至是残酷的竞争，虽然我有意识，但我却没有感觉，没有任何想要竞争的念头，只是和平常一样，做完作业了事。连我自己都觉得不可思议。但却很无奈。有思想却没有行动，真是可悲。最幸福的莫过于作业很少交，就算要交，只要和科代表哈喇一下就安全了。所以作业可做可不做，而我是读理科的所以不怕被老师留下来背课文。作业不写是常有的事，上课不认真也是常事，因为老师在那时都已经采取放任的态度，上课可以睡觉却不可以说话，你可以翘课但是只能在家不能外出，还要家长写证明，证明你在家。感觉找到了一丝的平衡，也大约感到高三并不是可悲的，至少我还有一丝的权利---就是拿我的前途开玩笑。我并不想，我想回到我中考时的状态，我试着努力，但我做不到。我恨我自己，但我又不时的给自己找借口。一种近乎消极的态度。
<br>  高考在即我也越发的轻松，越发的感到自由的热切呼唤。越发的嚣张，稍有一点的不顺心就大发脾气，这时是没人和我吵架的，他们只是觉得我要高考，紧张而已，所以对我非常的宽容。我也毫不客气的接受了他们的“好意”。也许是离高考没几天了，我也变的怀恋起来，有时甚至有不想高考，只想过高三的日子的念头，但是这个念头很快被我打消了，因为我热爱自由，没有人能够阻止我。也许我高三的唯一热趣就是看我自认为是偶像的人。他个子很高，瘦瘦的，很健康的形象，他爱打篮球。我也很喜欢看篮球，我懂得NBA，懂得Jorden,懂得O''neal,懂得今年的MVP是谁,懂得今天有谁的比赛,我是湖人的超级球迷,因为我喜欢看湖人队打球的霸气,喜欢O''neal,喜欢看他站在三秒区内的投球。虽然我看球的时间有限，但我总能知道结果，就是看篮球杂志，看着他们投球的精美照片，我就觉得很快乐。同学都说偶像很可爱，但是我就是不想和他讲话，只是在旁边偷看。看他笑，看他打闹，看他被老师抓去教育。我就觉得自己很幸福。初次看到他是在高中开学的前几天，有一次在走廊上无意间看到的。当时并没有觉得他长的帅，只是觉得他的脸很红，像新疆来的，也就没有放在心上。后来到了高三，年段分班，我和他在同班。在分班后的那次校运会上，我去替同学加油，看到他在跳高，我也就顺便走过去，然后就觉得他很帅，也许这就叫做一见钟情---很土的词。我知道不可能当他的女朋友，所以我自觉的称他为“偶像”。自觉的回避话题。每当有人问起，我就回答：“偶像是拿来欣赏的，而不是拿来爱的。”
<br>  毕业了，同学们事情很多，一会儿要拍照，一会儿要毕业留恋，有点伤感的情绪。毕业照分下来了，首先看我自己是否被拍丑了，然后看他的位置在哪，看他的神情。看着他的照片很伤心，即而是长叹一声。收起照片，我以为从此就可以慢慢的淡忘。还以为自己很潇洒，是那种不被感情束缚的流浪的灵魂。还以为他只是我生命中的过客，不会给我带来情绪上的影响。直到那天我在车站看到了他，看到他和别的女孩子在一起，虽然我早就知道他有女朋友了，就在我刚毕业不久的母校读初中。但我原已尘封的感情就象泉水一样不停的往上涌，制止不住。我假装没看到，从他傍边静静的走过，嘴角反射性的上翘，这种表情不知是否在嘲笑我自己，或者庆幸自己能逃脱这份感情。
<br>  我想他，在每一个晴朗的夜晚。
<br>  彭军的声音消失了，代替他声音的是响亮的广告声。我关了随身听，写下了这篇文章。
<br>
<br>
<br>                                                           ---记，写到一半时突然觉得笔墨羞涩，故后半篇是今 晚完成。
<br>                                         
<br>                                                                                      2002年9月29日晚', '今天我听了久违的彭军，熟悉的声音，温暖的感觉。听着他说的话题，很有感觉。

他的节目拌我走过了整个高中生涯。当初是几个同学拉我一起分享的，并没有太在意，只是抱着听听看的心情。没想到，这一听就是三年，从不间断。每每听到他的声音就会有很舒服的感觉，淡淡的忧伤，湿湿的味道。

整个高三我就是在这样声音中度过，并不真正的快乐，只是在生活中找动力，让我可以继续读书，继续有理想，继续生活着。日复一日，我也毕业了。毕业后，我没有再听过彭军，真的，一点也没有。我也不知道是怎么过的。只是在某个巧合的时间里，我又一次听到了彭军，这时我才意识到我有两个多月没听到彭军了。从这以后我一直提醒我自己要听要听，可都因为这样那样的事给耽误了。直到今天，我终于再一次听到了彭军。今天是9月25日，还是彭军舒服的声音，很有熟悉的味道。话题还是那么的接近我们，我在他的声音中思考，在播放的音乐中畅游。想起同学，想起往事，想起我那混日子时的不快乐。

高三的感觉，怎么说呢？最痛苦的是每天要有意识的提醒自己是高三的学生，要努力啊，要拼，要写很多的练习，要面对来自各方的压力，虽然他们是善意的，但我还是觉得没必要。最害怕的是我居然没有任何感觉我即将高考，即将面临激烈甚至是残酷的竞争，虽然我有意识，但我却没有感觉，没有任何想要竞争的念头，只是和平常一样，做完作业了事。连我自己都觉得不可思议。但却很无奈。有思想却没有行动，真是可悲。最幸福的莫过于作业很少交，就算要交，只要和科代表哈喇一下就安全了。所以作业可做可不做，而我是读理科的所以不怕被老师留下来背课文。作业不写是常有的事，上课不认真也是常事，因为老师在那时都已经采取放任的态度，上课可以睡觉却不可以说话，你可以翘课但是只能在家不能外出，还要家长写证明，证明你在家。感觉找到了一丝的平衡，也大约感到高三并不是可悲的，至少我还有一丝的权利---就是拿我的前途开玩笑。我并不想，我想回到我中考时的状态，我试着努力，但我做不到。我恨我自己，但我又不时的给自己找借口。一种近乎消极的态度。

高考在即我也越发的轻松，越发的感到自由的热切呼唤。越发的嚣张，稍有一点的不顺心就大发脾气，这时是没人和我吵架的，他们只是觉得我要高考，紧张而已，所以对我非常的宽容。我也毫不客气的接受了他们的“好意”。也许是离高考没几天了，我也变的怀恋起来，有时甚至有不想高考，只想过高三的日子的念头，但是这个念头很快被我打消了，因为我热爱自由，没有人能够阻止我。也许我高三的唯一热趣就是看我自认为是偶像的人。他个子很高，瘦瘦的，很健康的形象，他爱打篮球。我也很喜欢看篮球，我懂得NBA，懂得Jorden,懂得O''neal,懂得今年的MVP是谁,懂得今天有谁的比赛,我是湖人的超级球迷,因为我喜欢看湖人队打球的霸气,喜欢O''neal,喜欢看他站在三秒区内的投球。虽然我看球的时间有限，但我总能知道结果，就是看篮球杂志，看着他们投球的精美照片，我就觉得很快乐。同学都说偶像很可爱，但是我就是不想和他讲话，只是在旁边偷看。看他笑，看他打闹，看他被老师抓去教育。我就觉得自己很幸福。初次看到他是在高中开学的前几天，有一次在走廊上无意间看到的。当时并没有觉得他长的帅，只是觉得他的脸很红，像新疆来的，也就没有放在心上。后来到了高三，年段分班，我和他在同班。在分班后的那次校运会上，我去替同学加油，看到他在跳高，我也就顺便走过去，然后就觉得他很帅，也许这就叫做一见钟情---很土的词。我知道不可能当他的女朋友，所以我自觉的称他为“偶像”。自觉的回避话题。每当有人问起，我就回答：“偶像是拿来欣赏的，而不是拿来爱的。”

毕业了，同学们事情很多，一会儿要拍照，一会儿要毕业留恋，有点伤感的情绪。毕业照分下来了，首先看我自己是否被拍丑了，然后看他的位置在哪，看他的神情。看着他的照片很伤心，即而是长叹一声。收起照片，我以为从此就可以慢慢的淡忘。还以为自己很潇洒，是那种不被感情束缚的流浪的灵魂。还以为他只是我生命中的过客，不会给我带来情绪上的影响。直到那天我在车站看到了他，看到他和别的女孩子在一起，虽然我早就知道他有女朋友了，就在我刚毕业不久的母校读初中。但我原已尘封的感情就象泉水一样不停的往上涌，制止不住。我假装没看到，从他傍边静静的走过，嘴角反射性的上翘，这种表情不知是否在嘲笑我自己，或者庆幸自己能逃脱这份感情。

我想他，在每一个晴朗的夜晚。

彭军的声音消失了，代替他声音的是响亮的广告声。我关了随身听，写下了这篇文章。

---记，写到一半时突然觉得笔墨羞涩，故后半篇是今 晚完成。

